 const k=x.package.name+'@'+x.package.version;
 const fix=(x.reasons||[]).find(r=>r.startsWith('Fix available:'))||'';
 (by[k]??=[]).push("'`${x.id} ${fix.replace('"'Fix available: ','')}"'`);
}
for (const [k, vals] of Object.entries(by).sort()) console.log(k+'"'\\n  '+[...new Set(vals)].sort().join('\\n  '));
